template:
body {
  font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
  background-color: #f4f6f9;
  margin: 40px;
}

.form-container {
  background-color: #ffffff;
  padding: 30px 40px;
  border-bottom-left-radius: 12px;
  border-bottom-right-radius: 12px;
  box-shadow: 0 8px 16px rgba(0, 0, 0, 0.1);
}

.form-container h2 {
  margin-top: 0;
  margin-bottom: 20px;
  font-size: 24px;
  color: #333;
  text-align: center;
}

.form-group {
  margin-bottom: 15px;
}

label {
  display: block;
  margin-bottom: 6px;
  font-weight: 500;
  color: #555;
}

input[type="text"] {
  width: 100%;
  padding: 10px 12px;
  border: 1px solid #ccc;
  border-radius: 8px;
  box-sizing: border-box;
  font-size: 14px;
}

.button-row {
  display: flex;
  justify-content: flex-end;
  gap: 10px;
  margin-top: 20px;
}

.btn {
  padding: 10px 20px;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-size: 16px;
  color: white;
}

.btn-delete {
  background-color: #bb0000;
}

.btn-save {
  background-color: #0495c9;
}

.btn-save:hover {
  background-color: #357ebd;
}

.btn-upgrade {
  background-color: #dc3545;
}

.btn-upgrade:hover {
  background-color: #a71d2a;
}

.notif {
  width: 80%;
  border: 1px;
  border-radius: 8px;
  background-color: lightblue;
  color: black;
  font-weight: bold;
  margin: 8px;
  padding: 8px;
  display: flex;
  justify-content: center;
  align-items: center;
}

.menu {
  color: white;
  text-decoration: none;
  padding: 8px 12px;
  display: block;
}

const url=new URL(window.location.href);
const urlParams=new URLSearchParams(window.location.search);
const action=urlParams.get('action');
const select=document.getElementById("list");
var current = "c_";
if (localStorage.getItem("current_page")) current = localStorage.getItem("current_page");

if (action) {
  document.getElementById('notif').innerHTML=action;
  document.getElementById('notif').style.backgroundColor='lightgreen';
}

document.getElementById('menu_create').onclick=function() {
  current="c_";
  localStorage.setItem("current_page", current);
  document.getElementById('create').style.display='block';
  document.getElementById('recreate').style.display='none';
  document.getElementById('restart').style.display='none';
  document.getElementById('delete').style.display='none';
  document.getElementById('menu_create').style.color='white';
  document.getElementById('menu_recreate').style.color='grey';
  document.getElementById('menu_restart').style.color='grey';
  document.getElementById('menu_delete').style.color='grey';
}

document.getElementById('menu_recreate').onclick=function() {
  current="u_";
  localStorage.setItem("current_page", current);
  document.getElementById('recreate').style.display='block';
  document.getElementById('restart').style.display='none';
  document.getElementById('create').style.display='none';
  document.getElementById('delete').style.display='none';
  document.getElementById('menu_recreate').style.color='white';
  document.getElementById('menu_create').style.color='grey';
  document.getElementById('menu_restart').style.color='grey';
  document.getElementById('menu_delete').style.color='grey';
}

document.getElementById('menu_restart').onclick=function() {
  current="r_";
  localStorage.setItem("current_page", current);
  document.getElementById('recreate').style.display='none';
  document.getElementById('restart').style.display='block';
  document.getElementById('create').style.display='none';
  document.getElementById('delete').style.display='none';
  document.getElementById('menu_recreate').style.color='grey';
  document.getElementById('menu_create').style.color='grey';
  document.getElementById('menu_restart').style.color='white';
  document.getElementById('menu_delete').style.color='grey';
}

document.getElementById('menu_delete').onclick=function() {
  current="d_";
  localStorage.setItem("current_page", current);
  document.getElementById('recreate').style.display='none';
  document.getElementById('restart').style.display='none';
  document.getElementById('create').style.display='none';
  document.getElementById('delete').style.display='block';
  document.getElementById('menu_recreate').style.color='grey';
  document.getElementById('menu_restart').style.color='grey';
  document.getElementById('menu_create').style.color='grey';
  document.getElementById('menu_delete').style.color='white';
}

switch(current) {
  case "c_":  document.getElementById('menu_create').click();
              break;
  case "u_":  document.getElementById('menu_recreate').click();
              break;
  case "r_":  document.getElementById('menu_restart').click();
              break;
  case "d_":  document.getElementById('menu_delete').click();
              break;
}

url.searchParams.delete('action');
window.history.replaceState(window.history.state, '', url.href);
if (action) document.getElementById('menu_' + action.split(' ')[0].toLowerCase()).click();

for (let i=0; i < localStorage.length; i++) {
  const key=localStorage.key(i);
  if ( !key.startsWith ("__")) continue;
  const value=localStorage.getItem(key);

  const option=document.createElement("option");
  let cleaned = key.replace(/^__https?:\/\//, "").replace(/^_+|_+$/g, "");
  const [domain, suffix] = cleaned.split("__");
  option.text = domain.split(".")[0] + "-" + suffix;
  option.value=key;
  select.appendChild(option);
}

function remove() {
  document.getElementById('notif').innerHTML="Deleted";
  document.getElementById('notif').style.backgroundColor='lightred';
  const selectedIndex=select.selectedIndex;
  const id=select.value;
  const stored=localStorage.getItem(id);
  if ( !stored) return;
  localStorage.removeItem(id);
  select.remove(selectedIndex);
  change();
}

function save() {
  const data= {
    netbox: document.getElementById(current + "netbox").value,
      token: document.getElementById(current + "token").value,
      hostname: document.getElementById(current + "hostname").value,
      image: document.getElementById(current + "image").value,
      delay: document.getElementById(current + "delay") ? document.getElementById(current + "delay").value: "10000"
  }

  const newPaashup="__"+document.getElementById(current + "netbox").value+"__"+document.getElementById(current + "hostname").value;
  let update=true;
  if (localStorage.getItem(newPaashup)) update=false;
  localStorage.setItem(newPaashup, JSON.stringify(data));

  if (update) {
    const option=document.createElement("option");
    let cleaned = newPaashup.replace(/^__https?:\/\//, "").replace(/^_+|_+$/g, "");
    const [domain, suffix] = cleaned.split("__");
    option.text = domain.split(".")[0] + "-" + suffix;
    option.value=newPaashup;
    select.appendChild(option);
    option.selected = true;
  }
  document.getElementById('notif').innerHTML="Saved";
  document.getElementById('notif').style.backgroundColor='lightgreen';
  change(false);
}

function change(notif = true) {
  const id=select.value;
  const stored=localStorage.getItem(id);
  if ( !stored) return;
  if (notif) {
    document.getElementById('notif').innerHTML='<font color="grey">Welcome !</font>';
    document.getElementById('notif').style.backgroundColor='lightblue';
  }
  const data=JSON.parse(stored);

  for (let i of ["c_", "r_", "u_", "d_"]) {
    if (document.getElementById(i + "netbox")) document.getElementById(i + "netbox").value=data.netbox || "";
    if (document.getElementById(i + "token")) document.getElementById(i + "token").value=data.token || "";
    if (document.getElementById(i + "hostname")) document.getElementById(i + "hostname").value=data.hostname || "";
    if (document.getElementById(i + "image")) document.getElementById(i + "image").value=data.image || "";
    if (document.getElementById(i + "delay")) document.getElementById(i + "delay").value=data.delay || "10000";
  }
}

if (select.selectedIndex >=0) change();
